buildValidatorFunction ({ schema/*, method, url, httpPart */ }) {
  // Ajv does not support compiling two schemas with the same
  // id inside the same instance. Therefore if we have already
  // compiled the schema with the given id, we just return it.
  if (schema.$id) {
    const stored = this.ajv.getSchema(schema.$id)
    if (stored) {
      return stored
    }
  }

  return this.ajv.compile(schema)
}

export default async function (fastify: FastifyInstance) {
  fastify.addHook('onRequest', async (request, reply) => {
    if (request.url.startsWith('/api/auth/login')) {
      return
    }

    if (!request.session.user) {
      reply.unauthorized('You must be authenticated to access this route.')
    }
  })
}

@POST({url: '/'})
    public async storeInputMessage(
        req: FastifyRequest<IncomingMessage>,
        reply: FastifyReply<ServerResponse>
    ) {
        const value = req.body.message

        // Using Fastify instance to log that field was changed
        this.instance.log.info(`New value received: ${value}`)

        // Storing message in service
        this.messageService.message = value

        // Reply with OK
        return { message: 'OK' }
    }

(error, request, reply) => {
  fastify.log.debug(`Request url: `, request.req.url)
  fastify.log.debug(`Payload: `, request.body)
  fastify.log.error(`Error occurred: `, error)

  reply.status(500).send({ message: 'Error occurred during request' })
}

function fuzz (data) {
  const provider = new FuzzedDataProvider(data)

  const fmtString = provider.consumeRemainingAsString()
  try {
    fastContentTypeParse.parse(fmtString)
  } catch (error) {
    // Ignore all expected errors
    if (!(error instanceof TypeError)) {
      throw error
    }
  }
}

function SerializerSelector () {
  return function buildSerializerFactory (externalSchemas, serializerOpts) {
    const fjsOpts = Object.assign({}, serializerOpts, { schema: externalSchemas })
    return responseSchemaCompiler.bind(null, fjsOpts)
  }
}

async function runBenchmarks () {
  let maxNameLength = 0
  for (const benchmark of benchmarks) {
    maxNameLength = Math.max(benchmark.name.length, maxNameLength)
  }

  for (const benchmark of benchmarks) {
    benchmark.name = benchmark.name.padEnd(maxNameLength, '.')
    const resultMessage = await runBenchmark(benchmark)
    console.log(resultMessage)
  }
}

function replaceRouteParamPattern (pattern) {
  if (pattern.match(routeMixedParamPattern)) {
    return pattern.replace(routeMixedParamPattern, ':')
  } else if (pattern.match(routeParamPattern)) {
    return pattern.replace(routeParamPattern, '/:')
  }

  return pattern
}

function enrichError (err) {
  // Hack SyntaxError message so that we provide
  // the line number to the user, otherwise they
  // will be left in the cold.
  if (err instanceof SyntaxError) {
    err.message += ' at ' + err.stack.split('\n', 1)[0]
  }

  return err
}

function requireFastifyForModule (modulePath) {
  try {
    const basedir = path.resolve(process.cwd(), modulePath)
    const module = require(resolveFrom.silent(basedir, 'fastify') || 'fastify')

    return { module }
  } catch (e) {
    exit('unable to load fastify module')
  }
}

function onEnd (err) {
  // Client disconnection during streaming is expected and handled by Fastify.
  // Do not log "premature close" errors at error level since they are not
  // actual errors - they occur when clients disconnect mid-response.
  // See: https://github.com/fastify/fastify-compress/issues/382
  if (err && err.message !== 'premature close') {
    this.log.error(err)
  }
}

function handleCorsOptionsCallbackDelegator (optionsResolver, fastify, req, reply, next) {
  optionsResolver(req, (err, options) => {
    if (err) {
      next(err)
    } else {
      addCorsHeadersHandler(fastify, normalizeCorsOptions(options, true), req, reply, next)
    }
  })
}

function execRedis (redisClient, method, args) {
  return new Promise(function (resolve, reject) {
    args.push(function (err, result) {
      if (err) return reject(err)
      resolve(result)
    })
    redisClient[method].apply(redisClient, args)
  })
}

private getStrategyName (nameOrInstance: string | Strategy): string {
  if (typeof nameOrInstance === 'string') {
    return nameOrInstance
  } else if (nameOrInstance.name) {
    return nameOrInstance.name
  } else {
    return nameOrInstance.constructor.name
  }
}

function getPluginName (fn) {
  if (fn.name.length > 0) return fn.name

  const stackTraceLimit = Error.stackTraceLimit
  Error.stackTraceLimit = 10
  try {
    throw new Error('anonymous function')
  } catch (e) {
    Error.stackTraceLimit = stackTraceLimit
    return extractPluginName(e.stack)
  }
}

function (routeOptions = {}) {
  // NOTE: Optionally override and set global: false here for route specific
  // options, which then allows you to use `global: true` should you
  // wish to during initial registration below.
  const options = { ...this.options, ...routeOptions, global: false }
  const store = new KnexStore(options)
  store.routeKey(routeOptions.routeInfo.method + routeOptions.routeInfo.url)
  return store
}

function createLimiterArgs (pluginComponent, globalParams, options) {
  if (typeof options === 'object') {
    const newPluginComponent = Object.create(pluginComponent)
    const mergedRateLimitParams = mergeParams(globalParams, options, { routeInfo: {} })
    newPluginComponent.store = newPluginComponent.store.child(mergedRateLimitParams)
    return [newPluginComponent, mergedRateLimitParams]
  }

  return [pluginComponent, globalParams]
}

function RedisStore (continueExceeding, exponentialBackoff, redis, key = 'fastify-rate-limit-') {
  this.continueExceeding = continueExceeding
  this.exponentialBackoff = exponentialBackoff
  this.redis = redis
  this.key = key

  if (!this.redis.rateLimit) {
    this.redis.defineCommand('rateLimit', {
      numberOfKeys: 1,
      lua
    })
  }
}

function (req, reply) {
  const stream = new ReadableStream({
    start (controller) {
      controller.enqueue(payload)
      controller.close()
    }
  })
  return new Response(stream, {
    status: 200,
    headers: {
      'content-type': 'application/json; charset=utf-8'
    }
  })
}

function () {
  this[kReplyHijacked] = true
  // Clear handler timeout and signal — hijacked replies manage their own lifecycle
  if (this.request[kRequestSignal]) {
    clearTimeout(this.request[kTimeoutTimer])
    this.request[kTimeoutTimer] = null
    if (this.request[kOnAbort]) {
      this.request.raw.removeListener('close', this.request[kOnAbort])
      this.request[kOnAbort] = null
    }
  }
  return this
}

function preSerializationHook (reply, payload) {
  if (reply[kRouteContext].preSerialization !== null) {
    preSerializationHookRunner(
      reply[kRouteContext].preSerialization,
      reply.request,
      reply,
      payload,
      preSerializationHookEnd
    )
  } else {
    preSerializationHookEnd(null, undefined, reply, payload)
  }
}

function validateAsyncParams (validatePromise, context, request) {
  return validatePromise
    .then((paramsResult) => {
      if (paramsResult) {
        return wrapValidationError(paramsResult, 'params', context.schemaErrorFormatter)
      }

      return validate(context, request, { skipParams: true })
    })
}

function validateAsyncBody (validatePromise, context, request) {
  return validatePromise
    .then((bodyResult) => {
      if (bodyResult) {
        return wrapValidationError(bodyResult, 'body', context.schemaErrorFormatter)
      }

      return validate(context, request, { skipParams: true, skipBody: true })
    })
}

function validateAsyncQuery (validatePromise, context, request) {
  return validatePromise
    .then((queryResult) => {
      if (queryResult) {
        return wrapValidationError(queryResult, 'querystring', context.schemaErrorFormatter)
      }

      return validate(context, request, { skipParams: true, skipBody: true, skipQuery: true })
    })
}

function validateAsyncHeaders (validatePromise, context, request) {
  return validatePromise
    .then((headersResult) => {
      if (headersResult) {
        return wrapValidationError(headersResult, 'headers', context.schemaErrorFormatter)
      }

      return false
    })
}

function bindInject (dispatchFunc, defaults) {
  defaults = toOptionsObject(defaults)

  return function boundInject (options, callback) {
    const mergedOptions = deepMerge(defaults, toOptionsObject(options))
    return inject(dispatchFunc, mergedOptions, callback)
  }
}

function (data, encoding, callback) {
  if (this.timeoutHandle) {
    clearTimeout(this.timeoutHandle)
  }
  http.ServerResponse.prototype.write.call(this, data, encoding, callback)
  if (this._lightMyRequest.stream) {
    return this._lightMyRequest.stream.push(Buffer.from(data, encoding))
  } else {
    this._lightMyRequest.payloadChunks.push(Buffer.from(data, encoding))
    return true
  }
}

function (data, encoding, callback) {
  if (data) {
    this.write(data, encoding)
  }

  http.ServerResponse.prototype.end.call(this, callback)

  this.emit('finish')

  // We need to emit 'close' otherwise stream.finished() would
  // not pick it up on Node v16

  this.destroy()
}

function serializeHeaders (response) {
  const headers = response._lightMyRequest.headers

  for (const headerName of Object.keys(headers)) {
    const headerValue = headers[headerName]
    if (Array.isArray(headerValue)) {
      headers[headerName] = headerValue.map(value => '' + value)
    } else {
      headers[headerName] = '' + headerValue
    }
  }
}
